//==================================ReadNLSAtStart=================================//
// Read the NLS info required to build the tab
void ProcessToolOperationsBaseClass::ReadNLSAtStart(CATUnicodeString strNLSName, CATUnicodeString strNLSPath)
{
	int index = 0;
	CATMsgCatalog msgCatalog;
	index = msgCatalog.LoadMsgCatalog(strNLSName.ConvertToChar(), strNLSPath.ConvertToChar());

	if (index == 0)
	{
		CATUnicodeString msg = "NLS file not available fo the below Package\n";
		msg.Append(strNLSName);
		msg.Append(" in the path ");
		msg.Append(strNLSPath);

		MRFGenericUtils::ShowErrorMessage(msg);
		return;

	}

	CATString nlsName = strNLSName, nls_UDFCount, featureNameToCreate;


	this->_strTabName = strNLSName;

	nls_UDFCount = nlsName;
	nls_UDFCount.Append(".UDFCount");

	CATUnicodeString  profileCountAsStr;
	int UDFCount = 0;
	profileCountAsStr = (msgCatalog.GetCatalogMsg(nls_UDFCount)).BuildMessage();
	profileCountAsStr.ConvertToNum(&UDFCount, "%d");

	CATUnicodeString UDFNameListLines[100], udfName;
	bool atleatOneProfileFound = false;
	
	//featureNameToCreate = nlsName;
	//featureNameToCreate.Append(".Feature.Name");
	// featureNameToCreate = CATMsgCatalog::BuildMessage(nlsName, featureNameToCreate);

	// this->_spFeatureNameToSet = featureNameToCreate;

	int UDFFound_Count = 0;
	for (int i = 1; i <= UDFCount; i++)
	{
		CATUnicodeString profileName = nlsName, CountAsStr, udfName, udfProductName, udfProductRev, inputParams, calculatedParams;

		profileName.Append(".UDF.");

		CountAsStr.BuildFromNum(i);
		profileName.Append(CountAsStr);

		udfName = profileName;
		udfName.Append(".Name");

		udfProductName = profileName;
		udfProductName.Append(".RefProductName");

		udfProductRev = profileName;
		udfProductRev.Append(".RefProductRev");

		inputParams = profileName;
		inputParams.Append(".InputParameters");

		calculatedParams = profileName;
		calculatedParams.Append(".CalculatedParameters");

		udfName = (msgCatalog.GetCatalogMsg(udfName.ConvertToChar())).BuildMessage();
		udfProductName = (msgCatalog.GetCatalogMsg(udfProductName.ConvertToChar())).BuildMessage();
		udfProductRev = (msgCatalog.GetCatalogMsg(udfProductRev.ConvertToChar())).BuildMessage();
		inputParams = (msgCatalog.GetCatalogMsg(inputParams.ConvertToChar())).BuildMessage();
		calculatedParams = (msgCatalog.GetCatalogMsg(calculatedParams.ConvertToChar())).BuildMessage();

		UDFInfo *pUDFInfo = new UDFInfo();
		pUDFInfo->udfName = udfName;
		pUDFInfo->udfProductName = udfProductName;
		pUDFInfo->udfProductRev = udfProductRev;

		string inputParm = inputParams.ConvertToChar();
		stringstream  fileStream(inputParm);

		while (fileStream.good())
		{
			string parmName;
			getline(fileStream, parmName, ',');
			CATUnicodeString temp = parmName.c_str();
			pUDFInfo->strInputParmList.Append(temp);

		}

		string calculatedParm = calculatedParams.ConvertToChar();
		stringstream  fileStreamCal(calculatedParm);

		while (fileStreamCal.good())
		{
			string parmName;
			getline(fileStreamCal, parmName, ',');
			CATUnicodeString temp = parmName.c_str();
			pUDFInfo->strCalcParmList.Append(temp);

		}

		_pListOfUDFInfo.Append(pUDFInfo);
	}
}
