//==================================GetUDFParametersInfo====================================//
// Populate multilist with the parameters from UDF Instance
void ProcessToolOperationsBaseClass::GetUDFParametersInfo(CATDlgMultiList *pMultiListInputParm, CATDlgMultiList *pMultiListCalculated)
{
	//NLS file conatins the list of parameters to be considered for further operations. So, only parameters of name in the NLS file are stored 

	if (pMultiListInputParm == NULL_var || pMultiListCalculated == NULL_var)
		return;

		int udfIndex = this->GetIndexUDFActive();

		if (_pListOfUDFInfo.Size() >= udfIndex && udfIndex > 0)
		{
			UDFInfo *pUDFInfo = (UDFInfo*)_pListOfUDFInfo[udfIndex];

			if (pUDFInfo)
			{
				pUDFInfo->spListOfInputParm.RemoveAll();
				pUDFInfo->spListOfCalculatedParam.RemoveAll();

				CATIUdfFeatureInstance_var spUDFInst = pUDFInfo->spUDFInstance;

				if (spUDFInst == NULL_var)
				{
					pMultiListInputParm->ClearLine();
					pMultiListCalculated->ClearLine();

					return;
				}

				CATListValCATBaseUnknown_var *spListOfParmPublished = NULL;
				spUDFInst->GetParameters(spListOfParmPublished);
				CATListOfCATUnicodeString strCompletedInputParamList;

				if (NULL != spListOfParmPublished)
				{
					for (int i = 1; i <= spListOfParmPublished->Size(); i++)
					{
						CATICkeParm_var spParm = (*spListOfParmPublished)[i];
						if (!spParm)
							continue;
						CATUnicodeString ParameterName = MRFGenericUtils::GetParmNameSplittedFromCATICkeParm(spParm);

						if (!spParm->IsReadOnly())
						{
							if (pUDFInfo->strInputParmList.Locate(ParameterName)) //Checking whether the parameter defined in NLS (InputParameters) is matching with the read parameter
							{
								pUDFInfo->spListOfInputParm.Append(spParm);
								strCompletedInputParamList.Append(ParameterName);
							}
						}
						else if (spParm->IsReadOnly())
						{
							if (pUDFInfo->strCalcParmList.Locate(ParameterName)) //Checking whether the parameter defined in NLS (InputParameters) is matching with the read parameter
							{
								pUDFInfo->spListOfCalculatedParam.Append(spParm);
							}
						}
					}
				}

					//If all the parameters are not recognized from the NLS and the UDF instance, then rest of the parameters will be searched in the spec tree.
					int inputParamCount = pUDFInfo->spListOfInputParm.Size();
					if (inputParamCount < pUDFInfo->strInputParmList.Size())
					{
						if (NULL_var == _spMechFeatOnPart)
						{
							CATIMmiMechanicalFeature_var spMechPartFeature;
							CATIMmiMechanicalFeature_var spUDFInstFeature = spUDFInst;
							if (NULL_var != spUDFInstFeature)
								spUDFInstFeature->GetMechanicalPart(spMechPartFeature);
							if (NULL_var != spMechPartFeature)
								_spMechFeatOnPart = spMechPartFeature;
						}

						int j = 1;
						while (j <= pUDFInfo->strInputParmList.Size())
						{
							CATUnicodeString strParamName = pUDFInfo->strInputParmList[j];
							if (!strCompletedInputParamList.Locate(strParamName))
							{
								CATICkeParm_var spInputParameter;
								GetParamFromTree(strParamName, spInputParameter);

								if (NULL_var != spInputParameter && !pUDFInfo->spListOfInputParm.Locate(spInputParameter))
								{
									pUDFInfo->spListOfInputParm.Append(spInputParameter);
									strCompletedInputParamList.Append(strParamName);
								}
							}
							j++;
						}
					}
				
				int totalParmCount = pUDFInfo->spListOfInputParm.Size() + pUDFInfo->spListOfCalculatedParam.Size(), rowIndex = 0, columnIndex = 0;
				//------------Set Multi List UI Starts--//
					if (pMultiListInputParm)
					{
						pMultiListInputParm->ClearLine();
						MRFGenericUtils::PopulateMultiListForCkeParmList(pMultiListInputParm, pUDFInfo->spListOfInputParm, rowIndex, columnIndex);
					}
					if (pMultiListCalculated)
					{
						pMultiListCalculated->ClearLine();
						MRFGenericUtils::PopulateMultiListForCkeParmList(pMultiListCalculated, pUDFInfo->spListOfCalculatedParam, rowIndex, columnIndex);
					}

					//------------Set Multi List UI Ends--//
			}
			else
				return;
		}
		else
			return;
}
