//--------------------------------------------------------------------
//  ProcessToolOperationsBaseClass::ValuateSpinner()
//  Valuate the Spinner value
//--------------------------------------------------------------------
void ProcessToolOperationsBaseClass::ValuateSpinner(CATDlgMultiList* &pMultiList, CATDlgSpinner* &pSpinnerParmVal, CATDlgLabel* &pLabelToSetParmName)
{

	int rowIndexFromMultiList = 0;


		if (pMultiList)
		{
			int rowSelectedCount = 0;
			rowSelectedCount = pMultiList->GetSelect(&rowIndexFromMultiList, 1);

			if (rowSelectedCount != 0)
				rowIndexFromMultiList += 1;//row index of multi list start from zero index so incremnent 1, so while getting parm from list, it wont crash
		}

	if (rowIndexFromMultiList == 0)
		return;

	int udfIndex = this->GetIndexUDFActive();

	if (_pListOfUDFInfo.Size() >= udfIndex && udfIndex > 0)
	{
		UDFInfo *pUDFInfo = (UDFInfo*)_pListOfUDFInfo[udfIndex];

		if (pUDFInfo)
		{
			CATListValCATBaseUnknown_var parmList = pUDFInfo->spListOfInputParm;
			parmList.Append(pUDFInfo->spListOfCalculatedParam);

			if (parmList.Size() >= rowIndexFromMultiList && rowIndexFromMultiList > 0)
			{
				CATICkeParm_var spParmLoc = parmList[rowIndexFromMultiList];
				if (!!spParmLoc)
				{
					CATUnicodeString parmName = MRFGenericUtils::GetParmNameSplittedFromCATICkeParm(spParmLoc);
					CATUnicodeString parmValue = spParmLoc->Show();

					double fParmValue = 0.0;
					parmValue.ConvertToNum(&fParmValue);

					if (parmValue.Compare("true") == 1 || parmValue.Compare("true") == 2)
						fParmValue = 1;
					else if (parmValue.Compare("false") == 1 || parmValue.Compare("false") == 2)
						fParmValue = 0;
					if(pLabelToSetParmName)
						pLabelToSetParmName->SetTitle(parmName);
					//pSpinnerParmVal->SetCurrentValue((float)fParmValue, 0);

					this->_multiListIndexSelectedForEdit = rowIndexFromMultiList - 1; //this variable is to manage multi list, so decrementing 1

				}
			}

		}
	}
}
//--------------------------------------------------------------------
//  ProcessToolOperationsBaseClass::ValuateParameter()
//  Valuate the parameter
//--------------------------------------------------------------------
void ProcessToolOperationsBaseClass::ValuateParameter(CATDlgMultiList* &pMultiList, CATDlgSpinner* &pSpinnerParmVal, CATDlgLabel* &pLabelToSetParmName)
{
	int rowIndexFromMultiList = 0, multiListInd = _multiListIndexSelectedForEdit;


		if (pMultiList)
		{
			rowIndexFromMultiList = multiListInd +1; //this variable manages parmList so inceremented 1 in declaration
		}
		else
			return;


	if (rowIndexFromMultiList == 0 && pSpinnerParmVal == NULL && pLabelToSetParmName == NULL)
		return;

	int udfIndex = this->GetIndexUDFActive();

	if (_pListOfUDFInfo.Size() >= udfIndex && udfIndex > 0)
	{
		UDFInfo *pUDFInfo = (UDFInfo*)_pListOfUDFInfo[udfIndex];

		if (pUDFInfo)
		{
			CATListValCATBaseUnknown_var parmList = pUDFInfo->spListOfInputParm;
			parmList.Append(pUDFInfo->spListOfCalculatedParam);

			if (parmList.Size() >= rowIndexFromMultiList && rowIndexFromMultiList > 0)
			{
				CATICkeParm_var spParmLoc = parmList[rowIndexFromMultiList];
				if (!!spParmLoc)
				{
					CATUnicodeString parmName, parmValue;
					double fValue = 0;
					parmName = pLabelToSetParmName->GetTitle();
					fValue = pSpinnerParmVal->GetCurrentValue();

					parmValue.BuildFromNum(fValue);

					MRFGenericUtils::ValuateParmAsRespectiveUnit(spParmLoc, parmValue);

					pMultiList->SetColumnItem(2, spParmLoc->Show(), multiListInd, CATDlgDataModify);

				}
			}
		}
	}
}
//--------------------------------------------------------------------
//  ProcessToolOperationsBaseClass::ImportParametersFromExcel()
//  Import parameters from Excel
//--------------------------------------------------------------------
void ProcessToolOperationsBaseClass::ImportParametersFromExcel(CATListOfCATUnicodeString listParmName, CATListOfCATUnicodeString listParmValue, CATDlgMultiList* &pMultiListInputParm,CATDlgMultiList* &pMultiListCalculatedParm)
{
	int udfIndex = this->GetIndexUDFActive();

	if (_pListOfUDFInfo.Size() >= udfIndex && udfIndex > 0)
	{
		UDFInfo *pUDFInfo = (UDFInfo*)_pListOfUDFInfo[udfIndex];

		if (pUDFInfo)
		{
			CATListValCATBaseUnknown_var parmList = pUDFInfo->spListOfInputParm;
			//parmList.Append(pBeltInfo->spListOfCalculatedParam);

			for (int i = 1; i <= parmList.Size(); i++)
			{
				CATICkeParm_var spParmLoc = parmList[i];

				if (!spParmLoc)
					continue;

				CATUnicodeString parmName = MRFGenericUtils::GetParmNameSplittedFromCATICkeParm(spParmLoc);

				int indexOfParmNameFound = listParmName.Locate(parmName, 2); //2 is passed because the list starts with header from excel called "Parameter Name"

				if (indexOfParmNameFound != -1 && listParmValue.Size() >= indexOfParmNameFound && indexOfParmNameFound != 0)
				{
					CATUnicodeString parmValue = listParmValue[indexOfParmNameFound]; //passing the indexOfParmNameFound because the size of the listParmName and listParmValue will be equal

					MRFGenericUtils::ValuateParmAsRespectiveUnit(spParmLoc, parmValue);
				}
			}

			//------------Set Multi List UI Starts--//

			int totalParmCount = pUDFInfo->spListOfInputParm.Size() + pUDFInfo->spListOfCalculatedParam.Size(), rowIndex = 0, columnIndex = 0;

			if (pMultiListInputParm)
			{
				pMultiListInputParm->ClearLine();
				MRFGenericUtils::PopulateMultiListForCkeParmList(pMultiListInputParm, pUDFInfo->spListOfInputParm, rowIndex, columnIndex);
			}
			if (pMultiListCalculatedParm)
			{
				pMultiListCalculatedParm->ClearLine();
				MRFGenericUtils::PopulateMultiListForCkeParmList(pMultiListCalculatedParm, pUDFInfo->spListOfCalculatedParam, rowIndex, columnIndex);
			}

			//------------Set Multi List UI Ends--//
		}
	}

}
//--------------------------------------------------------------------
//  ProcessToolOperationsBaseClass::IsUDFInstantiated()
