//--------------------------------------------------------------------
bool ProcessToolOperationsBaseClass::IsUDFInstantiated()
{
	bool isUDFFound = false;
	int udfIndex = this->GetIndexOfUDFFromCombo();

	if (_pListOfUDFInfo.Size() >= udfIndex && udfIndex != 0)
	{
		UDFInfo *pUDFInfo = (UDFInfo*)_pListOfUDFInfo[udfIndex];

		if (pUDFInfo)
		{
			if (pUDFInfo->spUDFInstance != NULL_var)
				isUDFFound = true;
		}
	}

	return isUDFFound;
}

//======================================GetUDFInputsFromPrevPackage===========================================//
//--------------------------------------------------------------------
//  ProcessToolOperationsBaseClass::GetUDFInputsFromPrevPackage()
//  Get UDF inputs from previous package
//--------------------------------------------------------------------
HRESULT ProcessToolOperationsBaseClass::GetUDFInputsFromPrevPackage(CATListValCATBaseUnknown_var* & listOfUDFInputsToReplace, CATListValCATBaseUnknown_var InputParmsListToCheck,
	CATListValCATBaseUnknown_var OutPutListToCheck, CATListValCATBaseUnknown_var & OPlistOfInputsToSetInUDf)
{
	HRESULT rc = E_FAIL;
	////Set Inputs after deleting the old inputs

	if (listOfUDFInputsToReplace != NULL && listOfUDFInputsToReplace->Size() > 0)
	{
		CATListOfCATUnicodeString listOfParmName;
		if (InputParmsListToCheck.Size() > 0)
			listOfParmName = MRFGenericUtils::GetAliasNameFromList(InputParmsListToCheck);

		/*if (listOfParmName.Size() <= 0)
		{
			MRFGenericUtils::ShowErrorMessage("The following parameter not found in belt package, please publish the required parameter in belt and instantiate.\n" + parmName);
			return E_FAIL;
		}*/

		for (int i = 1; i <= listOfUDFInputsToReplace->Size(); i++)
		{
			CATICkeParm_var spParmLoc = (*listOfUDFInputsToReplace)[i];
			CATBaseUnknown_var spFeatType_UDFOutput;
			if (!spParmLoc)
				spFeatType_UDFOutput = (*listOfUDFInputsToReplace)[i];

			if (!!spParmLoc)
			{
				CATUnicodeString parmName = MRFGenericUtils::GetParmNameSplittedFromCATICkeParm(spParmLoc);
				bool parmFound = false;
				for (int i = 1; i <= listOfParmName.Size() && parmFound == false ; i++)
				{
					CATBaseUnknown_var spParmBelt = InputParmsListToCheck[i];
					if (!spParmBelt)
						continue;

					CATUnicodeString beltUdfParmName = listOfParmName[i];
					int jj = beltUdfParmName.Compare(parmName);
					if (beltUdfParmName.Compare(parmName) >= 1) //check with incase only case difference are there
					{
						OPlistOfInputsToSetInUDf.Append(spParmBelt);
						parmFound = true;
						rc = S_OK;
					}
				}

				if (parmFound == false)
				{
					CATBaseUnknown_var spInputParameter;
					parmFound = GetParamFromTree(parmName, spInputParameter);
					if (parmFound == true && NULL_var != spInputParameter)
						OPlistOfInputsToSetInUDf.Append(spInputParameter);

				}

				if (parmFound == false)
				{
					MRFGenericUtils::ShowErrorMessage("The following parameter not found in belt package, please publish the required parameter in belt and instantiate.\n" + parmName);
					return E_FAIL;
				}
			}
			else if (!!spFeatType_UDFOutput)
			{
				bool featFound = false;
				CATUnicodeString outputFeatNameFromBelt, outputFeatNameOfUDFBead;
				if (OPlistOfInputsToSetInUDf.Size() > 0)
					OutPutListToCheck.Append(OPlistOfInputsToSetInUDf);
				outputFeatNameOfUDFBead = MRFGenericUtils::GetAliasName(spFeatType_UDFOutput);
				for (int i = 1; i <= OutPutListToCheck.Size() && featFound == false; i++)
				{
					CATBaseUnknown_var spbeltoutpu = OutPutListToCheck[i];
					if (!spbeltoutpu)
						continue;

					outputFeatNameFromBelt = MRFGenericUtils::GetAliasName(spbeltoutpu);


					if (outputFeatNameFromBelt.Compare(outputFeatNameOfUDFBead) >= 1) //check with incase only case difference are there
					{
						if (!OPlistOfInputsToSetInUDf.Locate(spbeltoutpu))
							OPlistOfInputsToSetInUDf.Append(spbeltoutpu);

						featFound = true;
					}
				}

				if (featFound == false)
				{
					CATBaseUnknown_var spInputFeature;
					featFound = GetFeatureFromTree(outputFeatNameOfUDFBead, spInputFeature);
					if (featFound == true && NULL_var != spInputFeature)
						OPlistOfInputsToSetInUDf.Append(spInputFeature);
				}
				if (featFound == false)
				{
					MRFGenericUtils::ShowErrorMessage("The following parameter not found in belt package, please publish the required parameter in belt and instantiate.\n" + outputFeatNameOfUDFBead);
					return E_FAIL;
				}

			}
		}
	}

	return rc;
}
