//--------------------------------------------------------------------
//  ProcessToolOperationsBaseClass::GetActiveUDFParamsAndFeatPublished()
//  Get Parameters anf features published from the UDFs already existing in the structure
//--------------------------------------------------------------------
void ProcessToolOperationsBaseClass::GetActiveUDFParamsAndFeatPublished(CATListValCATBaseUnknown_var & spListOfInpuParmPub, CATListValCATBaseUnknown_var & listOfOutputFeatPub)
{
	int udfIndex = this->GetIndexUDFActive();
	
	if (this->_isToCreateFeature && this->_spFeatureCreated != NULL_var)
	{
		listOfOutputFeatPub.Append(this->_spFeatureCreated); // if the current package is a feature add that feature respective to the current package also as a published feature

	}

	if (_pListOfUDFInfo.Size() >= udfIndex && udfIndex > 0)
	{
		UDFInfo *pUDFInfo = (UDFInfo*)_pListOfUDFInfo[udfIndex];
		
		if (this->IsUDFInstantiated() == false)
		{
			CATUnicodeString packageName = "UDF under the below package is not found\n"; 
			packageName.Append(this->GetTabName());

			MRFGenericUtils::ShowErrorMessage(packageName);
			return;
		}

		if (pUDFInfo)
		{
			CATIUdfFeatureInstance_var spUDFInst = pUDFInfo->spUDFInstance;
			if (!!spUDFInst)
			{
				CATListValCATBaseUnknown_var* listOfParam = NULL;
				spUDFInst->GetParameters(listOfParam);
				if (listOfParam != NULL)
				{
					spListOfInpuParmPub.Append(*listOfParam);
				}
			}
			//spListOfInpuParmPub.Append(pUDFInfo->spListOfInputParm);
			//spListOfInpuParmPub.Append(pUDFInfo->spListOfCalculatedParam);

			listOfOutputFeatPub.Append(pUDFInfo->listOutputFeat);

		}
	}
}
